import { SERVICES } from "../constants";

export default function FormPanel({ form, setForm, editing, onSubmit, onCancel }) {

  const handleChange = (field) => (e) => {
    setForm((prev) => ({ ...prev, [field]: e.target.value }));
  };

  return (
    <aside className="pb-sidebar" style={{ padding: '20px', background: '#fff' }}>
      <h2>{editing ? "Editar" : "Novo Agendamento"}</h2>

      <div style={{ marginBottom: '15px' }}>
        <label>Nome do Cliente</label>
        <input
          style={{ width: '100%', padding: '8px', display: 'block' }}
          value={form.name || ""}
          onChange={handleChange("name")}
        />
      </div>

      <div style={{ marginBottom: '15px' }}>
        <label>Serviço</label>
        <select
          style={{ width: '100%', padding: '8px', display: 'block' }}
          value={form.service || ""}
          onChange={handleChange("service")}
        >
          <option value="">Selecione...</option>
          {SERVICES.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>
      </div>

      <button onClick={onSubmit} style={{ padding: '10px 20px', cursor: 'pointer' }}>
        {editing ? "Salvar" : "Confirmar"}
      </button>

      {editing && <button onClick={onCancel}>Cancelar</button>}
    </aside>
  );
}
